-        const mapping: []align(std.mem.page_size) u8 = @alignCast(kv.value.ptr[0..kv.value.size]);
+        std.debug.print("[cow] Unmapping CoW memory at {*}, size={d}\n", .{ kv.value.ptr, kv.value.size });
